# Whitelist of allowed tables and columns for security
ALLOWED_TABLES = os.environ.get('ALLOWED_TABLES', '').split(',') if os.environ.get('ALLOWED_TABLES') else []
ALLOWED_OPERATORS = {'=', '!=', '>', '<', '>=', '<=', 'LIKE', 'ILIKE', 'IN', 'NOT IN', 'IS NULL', 'IS NOT NULL', 'BETWEEN'}
ALLOWED_AGGREGATES = {'COUNT', 'SUM', 'AVG', 'MIN', 'MAX'}
ALLOWED_ORDER_DIRECTIONS = {'ASC', 'DESC'}

MAX_LIMIT = 10000
DEFAULT_LIMIT = 100


def get_db_connection():
    """Create and return a database connection."""
    conn = psycopg2.connect(**DB_CONFIG)
    return conn


def validate_identifier(identifier):
    """Validate that an identifier (table/column name) is safe."""
    if not identifier:
        return False
    # Only allow alphanumeric characters, underscores, and dots (for schema.table)
    pattern = re.compile(r'^[a-zA-Z_][a-zA-Z0-9_.]*$')
    return bool(pattern.match(identifier))


def validate_table_name(table_name):
    """Validate table name against whitelist if configured."""
    if not validate_identifier(table_name):
        return False, "Invalid table name format"
    if ALLOWED_TABLES and table_name not in ALLOWED_TABLES:
        return False, f"Table '{table_name}' is not in the allowed tables list"
    return True, None


def validate_column_names(columns):
    """Validate a list of column names."""
    for col in columns:
        # Allow aggregate functions like COUNT(column)
        agg_match = re.match(r'^(COUNT|SUM|AVG|MIN|MAX)\((\*|[a-zA-Z_][a-zA-Z0-9_.]*)\)$', col.upper())
        if agg_match:
            continue
        # Allow aliased columns like "column AS alias"
        alias_match = re.match(r'^([a-zA-Z_][a-zA-Z0-9_.]*)\s+AS\s+([a-zA-Z_][a-zA-Z0-9_]*)$', col, re.IGNORECASE)
        if alias_match:
            if not validate_identifier(alias_match.group(1)) or not validate_identifier(alias_match.group(2)):
                return False, f"Invalid column identifier in: {col}"
            continue
        if col != '*' and not validate_identifier(col):
            return False, f"Invalid column name: {col}"
    return True, None


def get_table_columns(conn, table_name):
    """Fetch actual column names from the database for a given table."""
    schema = 'public'
    table = table_name
    if '.' in table_name:
        parts = table_name.split('.', 1)
        schema = parts[0]
        table = parts[1]

    with conn.cursor() as cur:
        cur.execute(
            """
            SELECT column_name 
            FROM information_schema.columns 
            WHERE table_schema = %s AND table_name = %s
            """,
            (schema, table)
        )
        columns = [row[0] for row in cur.fetchall()]
    return columns


def build_select_clause(columns, table_columns=None):
    """Build the SELECT clause from column specifications."""
    if not columns or columns == ['*']:
        return '*', []

    select_parts = []
    for col in columns:
        # Handle aggregate functions
        agg_match = re.match(r'^(COUNT|SUM|AVG|MIN|MAX)\((\*|[a-zA-Z_][a-zA-Z0-9_.]*)\)$', col, re.IGNORECASE)
        if agg_match:
            func = agg_match.group(1).upper()
            inner = agg_match.group(2)
            if inner == '*':
                select_parts.append(f"{func}(*)")
            else:
                if table_columns and inner not in table_columns:
                    raise ValueError(f"Column '{inner}' does not exist in the table")
                select_parts.append(f"{func}({psycopg2.extensions.quote_ident(inner, None) if hasattr(psycopg2.extensions, 'quote_ident') else '\"' + inner.replace('\"', '\"\"') + '\"'})")
            continue

        # Handle aliased columns
        alias_match = re.match(r'^([a-zA-Z_][a-zA-Z0-9_.]*)\s+AS\s+([a-zA-Z_][a-zA-Z0-9_]*)$', col, re.IGNORECASE)
        if alias_match:
            col_name = alias_match.group(1)
            alias_name = alias_match.group(2)
            if table_columns and col_name not in table_columns:
                raise ValueError(f"Column '{col_name}' does not exist in the table")
            select_parts.append(f'"{col_name}" AS "{alias_name}"')
            continue

        if table_columns and col not in table_columns:
            raise ValueError(f"Column '{col}' does not exist in the table")
        select_parts.append(f'"{col}"')

    return ', '.join(select_parts), []


def safe_quote_ident(identifier):
    """Safely quote a SQL identifier."""
    # Double any existing double quotes and wrap in double quotes
    return '"' + identifier.replace('"', '""') + '"'


def build_where_clause(filters, table_columns=None):
    """Build WHERE clause from filter conditions."""
    if not filters:
        return '', []

    conditions = []
    params = []
    logical_op = filters.get('_logic', 'AND').upper()
    if logical_op not in ('AND', 'OR'):
        raise ValueError("Invalid logical operator. Use 'AND' or 'OR'")

    filter_list = filters.get('conditions', [])
    if not filter_list:
        # Try treating the entire filters dict as conditions (backward compatibility)
        for key, value in filters.items():
            if key.startswith('_'):
                continue
            if not validate_identifier(key):
                raise ValueError(f"Invalid column name in filter: {key}")
            if table_columns and key not in table_columns:
                raise ValueError(f"Column '{key}' does not exist in the table")
            conditions.append(f'{safe_quote_ident(key)} = %s')
            params.append(value)
        if conditions:
            return f" WHERE {f' {logical_op} '.join(conditions)}", params
        return '', []

    for f in filter_list:
        column = f.get('column')
        operator = f.get('operator', '=').upper()
        value = f.get('value')

        if not column or not validate_identifier(column):
            raise ValueError(f"Invalid column name in filter: {column}")

        if table_columns and column not in table_columns:
            raise ValueError(f"Column '{column}' does not exist in the table")

        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Invalid operator: {operator}. Allowed: {ALLOWED_OPERATORS}")

        col_ref = safe_quote_ident(column)

        if operator in ('IS NULL', 'IS NOT NULL'):
            conditions.append(f'{col_ref} {operator}')
        elif operator == 'BETWEEN':
            if not isinstance(value, list) or len(value) != 2:
                raise ValueError(f"BETWEEN operator requires a list of two values")
            conditions.append(f'{col_ref} BETWEEN %s AND %s')
            params.extend(value)
        elif operator in ('IN', 'NOT IN'):
            if not isinstance(value, list):
                raise ValueError(f"{operator} operator requires a list of values")
            placeholders = ', '.join(['%s'] * len(value))
            conditions.append(f'{col_ref} {operator} ({placeholders})')
            params.extend(value)
        else:
            conditions.append(f'{col_ref} {operator} %s')
            params.append(value)

    if conditions:
        return f" WHERE {f' {logical_op} '.join(conditions)}", params
    return '', []


def build_group_by_clause(group_by, table_columns=None):
    """Build GROUP BY clause."""
    if not group_by:
        return '', []

    validated = []
    for col in group_by:
        if not validate_identifier(col):
            raise ValueError(f"Invalid column name in GROUP BY: {col}")
        if table_columns and col not in table_columns:
            raise ValueError(f"Column '{col}' does not exist in the table")
        validated.append(safe_quote_ident(col))

    return f" GROUP BY {', '.join(validated)}", []


def build_having_clause(having_conditions):
    """Build HAVING clause for aggregate filters."""
    if not having_conditions:
        return '', []

    conditions = []
    params = []

    for h in having_conditions:
        aggregate = h.get('aggregate', '').upper()
        column = h.get('column', '*')
        operator = h.get('operator', '=').upper()
        value = h.get('value')

        if aggregate not in ALLOWED_AGGREGATES:
            raise ValueError(f"Invalid aggregate function: {aggregate}")
        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Invalid operator in HAVING: {operator}")
        if column != '*' and not validate_identifier(column):
            raise ValueError(f"Invalid column in HAVING: {column}")

        if column == '*':
            agg_expr = f"{aggregate}(*)"
        else:
            agg_expr = f"{aggregate}({safe_quote_ident(column)})"

        conditions.append(f'{agg_expr} {operator} %s')
        params.append(value)

    if conditions:
        return f" HAVING {' AND '.join(conditions)}", params
    return '', []


def build_order_by_clause(order_by, table_columns=None):
    """Build ORDER BY clause."""
    if not order_by:
        return ''

    parts = []
    for item in order_by:
        if isinstance(item, str):
            col = item
            direction = 'ASC'
        elif isinstance(item, dict):
            col = item.get('column')
            direction = item.get('direction', 'ASC').upper()
        else:
            raise ValueError(f"Invalid ORDER BY specification: {item}")

        if not validate_identifier(col):
            raise ValueError(f"Invalid column name in ORDER BY: {col}")
        if table_columns and col not in table_columns:
            raise ValueError(f"Column '{col}' does not exist in the table")
        if direction not in ALLOWED_ORDER_DIRECTIONS:
            raise ValueError(f"Invalid order direction: {direction}")

        nulls = ''
        if isinstance(item, dict) and 'nulls' in item:
            nulls_option = item['nulls'].upper()
            if nulls_option in ('FIRST', 'LAST'):
                nulls = f' NULLS {nulls_option}'

        parts.append(f'{safe_quote_ident(col)} {direction}{nulls}')

    return f" ORDER BY {', '.join(parts)}"


def build_join_clause(joins, table_columns_cache=None):
    """Build JOIN clauses."""
    if not joins:
        return '', []

    join_sql = ''
    allowed_join_types = {'INNER JOIN', 'LEFT JOIN', 'RIGHT JOIN', 'FULL OUTER JOIN', 'CROSS JOIN', 'LEFT OUTER JOIN', 'RIGHT OUTER JOIN'}

    for join in joins:
        join_type = join.get('type', 'INNER JOIN').upper()
        join_table = join.get('table')
        on_conditions = join.get('on', [])

        if join_type not in allowed_join_types:
            raise ValueError(f"Invalid JOIN type: {join_type}")

        valid, err = validate_table_name(join_table)
        if not valid:
            raise ValueError(f"Invalid join table: {err}")

        join_sql += f' {join_type} {safe_quote_ident(join_table)}'

        if join_type != 'CROSS JOIN':
            if not on_conditions:
                raise ValueError(f"JOIN requires ON conditions (except CROSS JOIN)")

            on_parts = []
            for cond in on_conditions:
                left_col = cond.get('left')
                right_col = cond.get('right')
                if not left_col or not right_col:
                    raise ValueError("JOIN ON condition requires 'left' and 'right' columns")

                # Allow table.column format
                left_parts = left_col.split('.')
                right_parts = right_col.split('.')

                for part in left_parts + right_parts:
                    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', part):
                        raise ValueError(f"Invalid column reference in JOIN: {left_col} or {right_col}")

                left_quoted = '.'.join(safe_quote_ident(p) for p in left_parts)
                right_quoted = '.'.join(safe_quote_ident(p) for p in right_parts)
                on_parts.append(f'{left_quoted} = {right_quoted}')

            join_sql += f' ON {" AND ".join(on_parts)}'

    return join_sql, []


@app.route('/api/v1/query', methods=['POST'])
def dynamic_query():
    """
    Execute a dynamic query based on JSON request body.

    Expected JSON format:
    {
        "table": "table_name",
        "columns": ["col1", "col2", "COUNT(col3)"],
        "filters": {
            "_logic": "AND",
            "conditions": [
                {"column": "col1", "operator": "=", "value": "some_value"},
                {"column": "col2", "operator": ">", "value": 100},
                {"column": "col3", "operator": "IN", "value": [1, 2, 3]},
                {"column": "col4", "operator": "BETWEEN", "value": [10, 50]},
                {"column": "col5", "operator": "IS NOT NULL"}
            ]
        },
        "joins": [
            {
                "type": "LEFT JOIN",
                "table": "other_table",
                "on": [{"left": "table_name.id", "right": "other_table.table_id"}]
            }
        ],
        "group_by": ["col1"],
        "having": [
            {"aggregate": "COUNT", "column": "col3", "operator": ">", "value": 5}
        ],
        "order_by": [
            {"column": "col1", "direction": "ASC"},
            {"column": "col2", "direction": "DESC", "nulls": "LAST"}
        ],
        "limit": 100,
        "offset": 0,
        "distinct": false
    }
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Request body must be JSON'}), 400

        # Extract and validate table name
        table_name = data.get('table')
        if not table_name:
            return jsonify({'error': 'Table name is required'}), 400

        valid, err = validate_table_name(table_name)
        if not valid:
            return jsonify({'error': err}), 400

        # Get connection and fetch actual table columns for validation
        conn = get_db_connection()
        try:
            table_columns = get_table_columns(conn, table_name)
            if not table_columns:
                return jsonify({'error': f"Table '{table_name}' not found or has no columns"}), 404

            # Build SELECT clause
            columns = data.get('columns', ['*'])
            valid, err = validate_column_names(columns)
            if not valid:
                return jsonify({'error': err}), 400

            try:
                select_clause, _ = build_select_clause(columns, table_columns)
            except ValueError as e:
                return jsonify({'error': str(e)}), 400

            # DISTINCT
            distinct = 'DISTINCT ' if data.get('distinct', False) else ''

            # Build FROM clause
            from_clause = safe_quote_ident(table_name)

            # Build JOIN clause
            join_clause = ''
            try:
                joins = data.get('joins', [])
                if joins:
                    join_clause, _ = build_join_clause(joins)
            except ValueError as e:
                return jsonify({'error': str(e)}), 400

            # Build WHERE clause
            params = []
            try:
                filters = data.get('filters', {})
                where_clause, where_params = build_where_clause(filters, table_columns)
                params.extend(where_params)
            except ValueError as e:
                return jsonify({'error': str(e)}), 400

            # Build GROUP BY clause
            try:
                group_by = data.get('group_by', [])
                group_by_clause, _ = build_group_by_clause(group_by, table_columns)
            except ValueError as e:
                return jsonify({'error': str(e)}), 400

            # Build HAVING clause
            try:
                having = data.get('having', [])
                having_clause, having_params = build_having_clause(having)
                params.extend(having_params)
            except ValueError as e:
                return jsonify({'error': str(e)}), 400

            # Build ORDER BY clause
            try:
                order_by = data.get('order_by', [])
                order_by_clause = build_order_by_clause(order_by, table_columns)
            except ValueError as e:
                return jsonify({'error': str(e)}), 400

            # LIMIT and OFFSET
            limit = min(int(data.get('limit', DEFAULT_LIMIT)), MAX_LIMIT)
            offset = int(data.get('offset', 0))
            if limit < 0 or offset < 0:
                return jsonify({'error': 'Limit and offset must be non-negative'}), 400

            # Assemble the full query
            query = f"SELECT {distinct}{select_clause} FROM {from_clause}{join_clause}{where_clause}{group_by_clause}{having_clause}{order_by_clause} LIMIT %s OFFSET %s"
            params.extend([limit, offset])

            # Also build a count query
            count_query = f"SELECT COUNT(*) FROM (SELECT {distinct}{select_clause} FROM {from_clause}{join_clause}{where_clause}{group_by_clause}{having_clause}) AS count_subquery"
            count_params = params[:-2]  # Exclude limit and offset

            # Execute queries
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                # Get total count
                cur.execute(count_query, count_params)
                total_count = cur.fetchone()['count']

                # Get results
                cur.execute(query, params)
                rows = cur.fetchall()

                # Convert to list of dicts
                results = [dict(row) for row in rows]

            return jsonify({
                'success': True,
                'data': results,
                'metadata': {
                    'table': table_name,
                    'total_count': total_count,
                    'returned_count': len(results),
                    'limit': limit,
                    'offset': offset,
                    'query': query,
                    'columns': columns
                }
            }), 200

        finally:
            conn.close()

    except psycopg2.Error as e:
        return jsonify({
            'error': 'Database error',
            'details': str(e)
        }), 500
    except (ValueError, TypeError, KeyError) as e:
        return jsonify({
            'error': 'Invalid request',
            'details': str(e)
        }), 400
    except Exception as e:
        return jsonify({
            'error': 'Internal server error',
            'details': str(e)
        }), 500


@app.route('/api/v1/tables', methods=['GET'])
def list_tables():
    """List available tables."""
    try:
        conn = get_db_connection()
        try:
            with conn.cursor() as cur:
                cur.execute("""
                    SELECT table_schema, table_name, table_type
                    FROM information_schema.tables
                    WHERE table_schema NOT IN ('pg_catalog', 'information_schema')
                    ORDER BY table_schema, table_name
                """)
                tables = []
                for row in cur.fetchall():
                    table_full_name = f"{row[0]}.{row[1]}" if row[0] != 'public' else row[1]
                    if ALLOWED_TABLES and table_full_name not in ALLOWED_TABLES and row[1] not in ALLOWED_TABLES:
                        continue
                    tables.append({
                        'schema': row[0],
                        'name': row[1],
                        'full_name': table_full_name,
                        'type': row[2]
                    })

            return jsonify({
                'success': True,
                'tables': tables
            }), 200
        finally:
            conn.close()
    except psycopg2.Error as e:
        return jsonify({'error': 'Database error', 'details': str(e)}), 500


@app.route('/api/v1/tables/<table_name>/columns', methods=['GET'])
def list_columns(table_name):
    """List columns for a specific table."""
    try:
        valid, err = validate_table_name(table_name)
        if not valid:
            return jsonify({'error': err}), 400

        conn = get_db_connection()
        try:
            schema = 'public'
            table = table_name
            if '.' in table_name:
                parts = table_name.split('.', 1)
                schema = parts[0]
                table = parts[1]

            with conn.cursor() as cur:
                cur.execute("""
                    SELECT column_name, data_type, is_nullable, column_default,
                           character_maximum_length, numeric_precision, numeric_scale
                    FROM information_schema.columns
                    WHERE table_schema = %s AND table_name = %s
                    ORDER BY ordinal_position
                """, (schema, table))

                columns = []
                for row in cur.fetchall():
                    columns.append({
                        'name': row[0],
                        'data_type': row[1],
                        'nullable': row[2] == 'YES',
                        'default': row[3],
                        'max_length': row[4],
                        'numeric_precision': row[5],
                        'numeric_scale': row[6]
                    })

            if not columns:
                return jsonify({'error': f"Table '{table_name}' not found"}), 404

            return jsonify({
                'success': True,
                'table': table_name,
                'columns': columns
            }), 200
        finally:
            conn.close()
    except psycopg2.Error as e:
        return jsonify({'error': 'Database error', 'details': str(e)}), 500


@app.route('/api/v1/tables/<table_name>/stats', methods=['GET'])
def table_stats(table_name):
    """Get basic statistics for a table."""
    try:
        valid, err = validate_table_name(table_name)
        if not valid:
            return jsonify({'error': err}), 400

        conn = get_db_connection()
        try:
            table_columns = get_table_columns(conn, table_name)
            if not table_columns:
                return jsonify({'error': f"Table '{table_name}' not found"}), 404

            quoted_table = safe_quote_ident(table_name)

            with conn.cursor() as cur:
                # Get row count
                cur.execute(f"SELECT COUNT(*) FROM {quoted_table}")
                row_count = cur.fetchone()[0]

                # Get column stats for numeric columns
                schema = 'public'
                table = table_name
                if '.' in table_name:
                    parts = table_name.split('.', 1)
                    schema = parts[0]
                    table = parts[1]

                cur.execute("""
                    SELECT column_name, data_type
                    FROM information_schema.columns
                    WHERE table_schema = %s AND table_name = %s
                    AND data_type IN ('integer', 'bigint', 'smallint', 'numeric', 'real', 'double precision')
                """, (schema, table))
                numeric_columns = cur.fetchall()

                column_stats = {}
                for col_name, data_type in numeric_columns:
                    quoted_col = safe_quote_ident(col_name)
                    cur.execute(f"""
                        SELECT 
                            MIN({quoted_col}) as min_val,
                            MAX({quoted_col}) as max_val,
                            AVG({quoted_col}::numeric) as avg_val,
                            COUNT({quoted_col}) as non_null_count,
                            COUNT(*) - COUNT({quoted_col}) as null_count
                        FROM {quoted_table}
                    """)
                    stats_row = cur.fetchone()
                    column_stats[col_name] = {
                        'data_type': data_type,
                        'min': float(stats_row[0]) if stats_row[0] is not None else None,
                        'max': float(stats_row[1]) if stats_row[1] is not None else None,
                        'avg': float(round(stats_row[2], 4)) if stats_row[2] is not None else None,
                        'non_null_count': stats_row[3],
                        'null_count': stats_row[4]
                    }

            return jsonify({
                'success': True,
                'table': table_name,
                'row_count': row_count,
                'column_count': len(table_columns),
                'columns': table_columns,
                'numeric_column_stats': column_stats
            }), 200
        finally:
            conn.close()
    except psycopg2.Error as e:
        return jsonify({'error': 'Database error', 'details': str(e)}), 500


